#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<int> d(n), p(n);
    for(int i=0;i<n;i++) cin>>d[i];
    for(int i=0;i<n;i++) cin>>p[i];
    vector<pair<int,int>> jobs; jobs.reserve(n);
    int maxd=0;
    for(int i=0;i<n;i++){
        jobs.emplace_back(p[i], d[i]);
        maxd = max(maxd, d[i]);
    }
    sort(jobs.begin(), jobs.end(), [](const auto& a, const auto& b){return a.first>b.first;});
    vector<char> slot(maxd+1, 0); // 1-indexed
    long long total=0;
    for(auto &job: jobs){
        int profit = job.first;
        int deadline = job.second;
        for(int t=min(deadline, maxd); t>=1; --t){
            if(!slot[t]){ slot[t]=1; total+=profit; break; }
        }
    }
    cout<<total;
    return 0;
}
